query:
fragment StreamConfigFragment on StreamConfig {
  name
  donationUrl
  streamOrder
  seo {
    title
    description
    keywords
    image {
      url
      title
      description
      __typename
    }
    __typename
  }
  sponsorCollection(limit: 100) {
    items {
      sys {
        id
        __typename
      }
      title
      url
      name
      logo {
        url
        title
        description
        __typename
      }
      __typename
    }
    __typename
  }
  __typename
}

query StreamsList {
  streamCollection(limit: 20, where: {CC_exists: true}) {
    items {
      sys {
        id
        __typename
      }
      name
      description
      playerName
      onAir
      streamTrackingId
      thumbnail {
        url
        title
        description
        __typename
      }
      ccConfig {
        ...StreamConfigFragment
        __typename
      }
      __typename
    }
    __typename
  }
}
